VALUES
  ('locality-6f0ba476-moex-00255', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '假設有商品X與商品Y，且此兩商品的供給曲線皆為水平線，需求曲線則為負斜率。若政府原已 對商品X課稅，現又對商品Y課稅，則在商品X與商品Y互為替代品或互補品兩種情況下，和 只對商品X課稅相比，其所產生之社會總超額負擔：', '["互為替代品的社會總超額負擔一定增加，而互為互補品的則可能降低", "互為替代品的社會總超額負擔可能降低，而互為互補品的一定增加", "兩者的社會總超額負擔一定都會增加", "兩者的社會總超額負擔可能降低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": "a633ee315514", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00256', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '在兩商品均為完全競爭市場，且消費者的所得固定下，如果對兩商品課徵相同從價稅率之單一稅 率25%，則等同於減少多少比例的所得？', '["10%", "20%", "30%", "40%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": "a633ee315514", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00257', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '在個人效用極大化、兩期消費選擇之生命週期模型中，假設利息費用可於計算所得時扣除，有關 利息所得課稅之敘述，下列何者錯誤？', '["對利息所得課稅所產生的所得效果將使當期消費減少", "對利息所得課稅所產生的替代效果將使當期消費增加", "對利息所得課稅，其對當期儲蓄影響不確定", "對利息所得課稅，若課稅前後的當期儲蓄不變，表示不會產生超額負擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": "a633ee315514", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00258', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '關於次佳理論（thetheoryofthesecondbest）之敘述，下列何者錯誤？', '["由LipseyandLancaster提出", "任何課稅都會導致效率損失，因此不是最好的選擇", "當存在市場扭曲時，課稅未必會增加超額負擔", "當存在外部性時，課稅可能提升社會福利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": "a633ee315514", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00259', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '關於自然獨占公用事業的訂價，下列敘述何者正確？', '["邊際成本訂價法能使此一市場達到效率，但使用者支付的價格未反應他們得到的利益", "應採邊際收入等於邊際成本訂價法，因為剛好沒有虧損，以免讓全民買單", "平均成本訂價法下的均衡產量大於邊際成本訂價法的均衡產量", "邊際收入等於邊際成本訂價法下產量最大"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": "a633ee315514", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00260', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', 'Edgeworth’smodel的最適所得稅隱含採用何種稅制？', '["比例所得稅", "線性累進所得稅", "定額稅", "完全累進的所得稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": "a633ee315514", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00261', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '對資本利得課稅，會發生閉鎖效果（lock-ineffect），下列敘述何者正確？', '["會使投資人快速移轉或出售資產", "會使公司減少股利給付", "會使投資人較不願意改變資產組合", "無論何時處理資產，投資人之租稅負擔的現值是固定的"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": "a633ee315514", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00262', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '假定資本可在國際市場自由移動，且國外資金的供給為完全有彈性。若政府只對本國的儲蓄課利 息所得稅，對國內的儲蓄和投資的影響為何？', '["儲蓄減少，投資減少", "儲蓄增加，投資減少", "儲蓄增加，投資增加", "儲蓄減少，投資不變"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": "a633ee315514", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00263', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '關於稅式支出（taxexpenditure）之敘述，下列何者錯誤？', '["會造成稅基侵蝕與稅收損失", "政府為達成特定的政策目的而產生", "須逐年經由國會預算審議程序的評估與審查", "形式上減輕納稅義務人稅負，實質上屬於政府支出的一環"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": "a633ee315514", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00264', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '甲稅前的預算線如下圖中的AB，政府課徵所得稅之後，預算線為CD。若政府實施將部分薪資存 入退休帳戶的金額可在當期所得扣除，於退休提領本金與利息時一併課稅，並對存入退休帳戶的 金額設定上限。下列敘述何者錯誤？', '["存入退休帳戶金額未達上限者，最適選擇落在ED", "存入退休帳戶金額未達上限者，僅產生所得效果", "存入退休帳戶金額超過上限者，最適選擇落在FE", "存入退休帳戶金額超過上限者，僅產生所得效果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": "a633ee315514", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
